        "path": "bright-memory-infinite-trainer/README.md",
        "content": "# Bright Memory: Infinite Trainer\n\nA memory trainer for the game Bright Memory: Infinite. This project provides a simple console-based trainer to modify in-game values like health, ammo, and score using memory manipulation (WriteProcessMemory/ReadProcessMemory).\n\n**Disclaimer:** This is for educational purposes only. Use at your own risk.\n\n## Features\n- Read current health, ammo, and score.\n- Set health to a custom value.\n- Set ammo to a custom value.\n- Set score to a custom value.\n- Simple menu-driven interface.\n\n## Requirements\n- .NET 6.0 or later\n- Windows OS (uses kernel32.dll)\n\n## Build\n```\ndotnet build\n```\n\n## Run\n```\ndotnet run --project BrightMemoryInfiniteTrainer\n```\n\n## Test\n```\ndotnet test\n```\n"
    },
    {
        "path": "bright-memory-infinite-trainer/BrightMemoryInfiniteTrainer/BrightMemoryInfiniteTrainer.csproj",
        "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net6.0</TargetFramework>\n    <ImplicitUsings>enable</ImplicitUsings>\n    <Nullable>enable</Nullable>\n  </PropertyGroup>\n\n  <ItemGroup>\n    <PackageReference Include=\"Microsoft.Win32.Registry\" Version=\"5.0.0\" />\n    <PackageReference Include=\"System.Diagnostics.Process\" Version=\"4.3.0\" />\n  </ItemGroup>\n\n</Project>\n"
    },
    {
        "path": "bright-memory-infinite-trainer/BrightMemoryInfiniteTrainer/Program.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace BrightMemoryInfiniteTrainer\n{\n    /// <summary>\n    /// Entry point for the Bright Memory: Infinite Trainer.\n    /// Provides a console menu to modify game memory.\n    /// </summary>\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Bright Memory: Infinite Trainer\");\n            Console.WriteLine(\"===============================\");\n\n            // Find the game process\n            Process? gameProcess = MemoryManager.FindProcess(\"BrightMemoryInfinite\");\n            if (gameProcess == null)\n            {\n                Console.WriteLine(\"Game process not found. Make sure Bright Memory: Infinite is running.\");\n                return;\n            }\n\n            Console.WriteLine($\"Found process: {gameProcess.ProcessName} (PID: {gameProcess.Id})\");\n\n            // Example memory addresses (these are placeholders — real addresses would need to be found via scanning)\n            // In a real trainer, these would be dynamically resolved.\n            IntPtr healthAddress = (IntPtr)0x00A1B2C0;\n            IntPtr ammoAddress = (IntPtr)0x00A1B2C4;\n            IntPtr scoreAddress = (IntPtr)0x00A1B2C8;\n\n            bool exit = false;\n            while (!exit)\n            {\n                Console.WriteLine(\"\\nOptions:\");\n                Console.WriteLine(\"1. Read Health\");\n                Console.WriteLine(\"2. Set Health\");\n                Console.WriteLine(\"3. Read Ammo\");\n                Console.WriteLine(\"4. Set Ammo\");\n                Console.WriteLine(\"5. Read Score\");\n                Console.WriteLine(\"6. Set Score\");\n                Console.WriteLine(\"7. Exit\");\n                Console.Write(\"Select an option: \");\n                string? input = Console.ReadLine();\n\n                switch (input)\n                {\n                    case \"1\":\n                        int health = MemoryManager.ReadInt(gameProcess, healthAddress);\n                        Console.WriteLine($\"Current Health: {health}\");\n                        break;\n                    case \"2\":\n                        Console.Write(\"Enter new health value: \");\n                        if (int.TryParse(Console.ReadLine(), out int newHealth))\n                        {\n                            MemoryManager.WriteInt(gameProcess, healthAddress, newHealth);\n                            Console.WriteLine(\"Health updated.\");\n                        }\n                        else\n                        {\n                            Console.WriteLine(\"Invalid input.\");\n                        }\n                        break;\n                    case \"3\":\n                        int ammo = MemoryManager.ReadInt(gameProcess, ammoAddress);\n                        Console.WriteLine($\"Current Ammo: {ammo}\");\n                        break;\n                    case \"4\":\n                        Console.Write(\"Enter new ammo value: \");\n                        if (int.TryParse(Console.ReadLine(), out int newAmmo))\n                        {\n                            MemoryManager.WriteInt(gameProcess, ammoAddress, newAmmo);\n                            Console.WriteLine(\"Ammo updated.\");\n                        }\n                        else\n                        {\n                            Console.WriteLine(\"Invalid input.\");\n                        }\n                        break;\n                    case \"5\":\n                        int score = MemoryManager.ReadInt(gameProcess, scoreAddress);\n                        Console.WriteLine($\"Current Score: {score}\");\n                        break;\n                    case \"6\":\n                        Console.Write(\"Enter new score value: \");\n                        if (int.TryParse(Console.ReadLine(), out int newScore))\n                        {\n                            MemoryManager.WriteInt(gameProcess, scoreAddress, newScore);\n                            Console.WriteLine(\"Score updated.\");\n                        }\n                        else\n                        {\n                            Console.WriteLine(\"Invalid input.\");\n                        }\n                        break;\n                    case \"7\":\n                        exit = true;\n                        break;\n                    default:\n                        Console.WriteLine(\"Invalid option.\");\n                        break;\n                }\n            }\n\n            Console.WriteLine(\"Exiting trainer.\");\n        }\n    }\n}\n"
    },
