        "path": "bright-memory-infinite-trainer/BrightMemoryInfiniteTrainer/MemoryManager.cs",
        "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\n\nnamespace BrightMemoryInfiniteTrainer\n{\n    /// <summary>\n    /// Provides low-level memory operations using Windows API.\n    /// </summary>\n    public static class MemoryManager\n    {\n        // Import necessary Windows API functions\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool CloseHandle(IntPtr hObject);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\n\n        [DllImport(\"kernel32.dll\", SetLastError = true)]\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\n\n        // Process access flags\n        private const uint PROCESS_VM_READ = 0x0010;\n        private const uint PROCESS_VM_WRITE = 0x0020;\n        private const uint PROCESS_VM_OPERATION = 0x0008;\n        private const uint PROCESS_QUERY_INFORMATION = 0x0400;\n\n        /// <summary>\n        /// Finds a process by its name (without .exe extension).\n        /// </summary>\n        /// <param name=\"processName\">Name of the process, e.g., \"BrightMemoryInfinite\".</param>\n        /// <returns>The first matching Process, or null if not found.</returns>\n        public static Process? FindProcess(string processName)\n        {\n            Process[] processes = Process.GetProcessesByName(processName);\n            if (processes.Length > 0)\n            {\n                return processes[0];\n            }\n            return null;\n        }\n\n        /// <summary>\n        /// Reads an integer from the target process's memory.\n        /// </summary>\n        /// <param name=\"process\">Target process.</param>\n        /// <param name=\"address\">Memory address to read from.</param>\n        /// <returns>The integer value read, or 0 on failure.</returns>\n        public static int ReadInt(Process process, IntPtr address)\n        {\n            IntPtr hProcess = OpenProcess(PROCESS_VM_READ | PROCESS_QUERY_INFORMATION, false, process.Id);\n            if (hProcess == IntPtr.Zero)\n            {\n                Console.WriteLine(\"Failed to open process for reading.\");\n                return 0;\n            }\n\n            byte[] buffer = new byte[4];\n            if (ReadProcessMemory(hProcess, address, buffer, buffer.Length, out int bytesRead))\n            {\n                CloseHandle(hProcess);\n                return BitConverter.ToInt32(buffer, 0);\n            }\n\n            Console.WriteLine(\"Failed to read memory.\");\n            CloseHandle(hProcess);\n            return 0;\n        }\n\n        /// <summary>\n        /// Writes an integer to the target process's memory.\n        /// </summary>\n        /// <param name=\"process\">Target process.</param>\n        /// <param name=\"address\">Memory address to write to.</param>\n        /// <param name=\"value\">The integer value to write.</param>\n        /// <returns>True if successful, false otherwise.</returns>\n        public static bool WriteInt(Process process, IntPtr address, int value)\n        {\n            IntPtr hProcess = OpenProcess(PROCESS_VM_WRITE | PROCESS_VM_OPERATION, false, process.Id);\n            if (hProcess == IntPtr.Zero)\n            {\n                Console.WriteLine(\"Failed to open process for writing.\");\n                return false;\n            }\n\n            byte[] buffer = BitConverter.GetBytes(value);\n            if (WriteProcessMemory(hProcess, address, buffer, buffer.Length, out int bytesWritten))\n            {\n                CloseHandle(hProcess);\n                return true;\n            }\n\n            Console.WriteLine(\"Failed to write memory.\");\n            CloseHandle(hProcess);\n            return false;\n        }\n    }\n}\n"
    },
